import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"冰枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/冰枪.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/冰枪.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/冰枪.md"};function l(i,e,_,p,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"冰枪",tabindex:"-1"},[n("冰枪 "),a("a",{class:"header-anchor",href:"#冰枪","aria-label":'Permalink to "冰枪"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="冰枪-1" tabindex="-1">冰枪 <a class="header-anchor" href="#冰枪-1" aria-label="Permalink to &quot;冰枪&quot;">​</a></h1><p>冰枪</p><p>价格：C+1250<br> 描述：《艾尔登法环》世界中存在的能赋予武器属性，战技的战灰之一。在取得时需要选定自身持有的一个武器，将战灰赋予其上。只有在装备那个武器时，才可以使用战灰的战技。<br> 这个战灰可以附着在所有的长柄武器和刺剑上。<br> 一柄武器仅可以被赋予一个战灰。战灰所选定的武器可以在一次长休时进行变更。<br> 【寒冷】：战灰所附带的属性之一，每在智力上具有2点附加成功，就在附加了本战灰的武器的攻击上获得1点器械加值，并且在以附加了本战灰的武器攻击时，额外对敌人造成1点冻寒伤害。<br> 【战技：冰枪】：侍奉“月之公主”妮的战士使用的战技。旋转武器之余唤出寒气，再顺势使出突刺，释放冰枪。<br> 以一个标准动作，消耗1点意志，你举起武器，发射冰枪。<br> 你进行一次白刃攻击，这次白刃攻击额外具有20米直线射程，并对直线射程上的所有敌人造成伤害，敌人以反射豁免。<br> 由于冰枪的性质，这次攻击还会附带伤害四分之一的冻结点数。<br> 冰枪是为妮公主而战的战士的战技，受到暗月的祝福，因而你每在智力上具有1点附加成功，就在该战技的攻击上具有2dp的神圣加值。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',5)])])}const f=r(d,[["render",l]]);export{m as __pageData,f as default};
